import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';

const STATUS_FILTERS = [
  { value: '',                label: 'All Events',       icon: '📊', color: 'var(--cyan-accent)' },
  { value: 'pending_approval',label: 'Pending Approval', icon: '⏳', color: '#f59e0b' },
  { value: 'published',       label: 'Published',        icon: '✅', color: '#10b981' },
  { value: 'rejected',        label: 'Rejected',         icon: '❌', color: '#ef4444' },
  { value: 'completed',       label: 'Completed',        icon: '🏁', color: 'var(--purple-light)' },
  { value: 'cancelled',       label: 'Cancelled',        icon: '🚫', color: '#6b7280' },
];

const STATUS_COLOR = {
  pending_approval: '#f59e0b',
  published:        '#10b981',
  rejected:         '#ef4444',
  completed:        'var(--purple-light)',
  cancelled:        '#6b7280',
  draft:            '#6b7280',
};

const STATUS_LABEL = {
  pending_approval: '⏳ Pending Approval',
  published:        '✅ Published',
  rejected:         '❌ Rejected',
  completed:        '🏁 Completed',
  cancelled:        '🚫 Cancelled',
  draft:            '📝 Draft',
};

const fmt = (d) =>
  d ? new Date(d).toLocaleDateString('en-US', { day: 'numeric', month: 'short', year: 'numeric' }) : '—';

export default function AdminEvents() {
  const [events, setEvents]         = useState([]);
  const [loading, setLoading]       = useState(true);
  const [statusFilter, setStatus]   = useState('');
  const [search, setSearch]         = useState('');

  const fetchAll = async () => {
    setLoading(true);
    try {
      const res = await api.get('/events/all?limit=500');
      setEvents(res.data.data || []);
    } catch {
      toast.error('Failed to load events');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchAll(); }, []);

  const approveEvent = async (id, title) => {
    try {
      await api.put(`/events/${id}/approve`);
      toast.success(`"${title}" approved and published!`);
      fetchAll();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to approve');
    }
  };

  const rejectEvent = async (id, title) => {
    const reason = prompt(`Reason for rejecting "${title}":`);
    if (reason === null) return;
    try {
      await api.put(`/events/${id}/reject`, { reason });
      toast.success(`"${title}" rejected`);
      fetchAll();
    } catch {
      toast.error('Failed to reject event');
    }
  };

  const filtered = events.filter(e => {
    const matchesStatus = !statusFilter || e.status === statusFilter;
    const matchesSearch = !search ||
      e.title?.toLowerCase().includes(search.toLowerCase()) ||
      e.community?.name?.toLowerCase().includes(search.toLowerCase()) ||
      e.createdBy?.name?.toLowerCase().includes(search.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const countFor = (s) => events.filter(e => e.status === s).length;

  return (
    <div className="page-wrapper">
      <div className="container">

        {/* Header */}
        <div style={{
          background: 'linear-gradient(135deg, rgba(15,25,35,0.8), rgba(10,18,26,0.9))',
          borderRadius: 'var(--border-radius-lg)',
          padding: '28px 32px',
          marginBottom: '32px',
          border: '1px solid rgba(245,158,11,0.2)',
          position: 'relative',
          overflow: 'hidden',
        }}>
          <div style={{
            position: 'absolute', top: -30, right: -30,
            width: 150, height: 150, borderRadius: '50%',
            background: 'radial-gradient(circle, rgba(245,158,11,0.08) 0%, transparent 70%)',
            pointerEvents: 'none',
          }} />
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'relative', zIndex: 1, flexWrap: 'wrap', gap: 16 }}>
            <div>
              <h1 style={{ fontFamily: 'var(--font-display)', fontSize: '1.8rem', marginBottom: 8 }}>
                EVENT <span className="gradient-text">MANAGEMENT</span>
              </h1>
              <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                <div style={{
                  display: 'flex', alignItems: 'center', gap: 6,
                  background: 'rgba(245,158,11,0.1)', padding: '4px 12px',
                  borderRadius: 20, fontSize: '0.85rem', color: '#f59e0b',
                }}>
                  <span>📅</span>
                  <span>{events.length} Total Events</span>
                </div>
                {countFor('pending_approval') > 0 && (
                  <div style={{
                    display: 'flex', alignItems: 'center', gap: 6,
                    background: 'rgba(245,158,11,0.15)', padding: '4px 12px',
                    borderRadius: 20, fontSize: '0.85rem', color: '#f59e0b',
                    fontWeight: 700, border: '1px solid rgba(245,158,11,0.3)',
                  }}>
                    ⏳ {countFor('pending_approval')} awaiting approval
                  </div>
                )}
              </div>
            </div>
            <Link to="/admin" className="btn btn-outline" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              ← Dashboard
            </Link>
          </div>
        </div>

        {/* Stats */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(6,1fr)', gap: 12, marginBottom: 28 }}>
          {STATUS_FILTERS.slice(1).map(f => (
            <div key={f.value} style={{
              background: 'rgba(10,18,26,0.6)', backdropFilter: 'blur(10px)',
              borderRadius: 12, padding: '12px', border: `1px solid ${f.color}20`,
              textAlign: 'center', cursor: 'pointer',
              outline: statusFilter === f.value ? `2px solid ${f.color}` : 'none',
            }} onClick={() => setStatus(statusFilter === f.value ? '' : f.value)}>
              <div style={{ fontSize: '1.2rem', marginBottom: 4 }}>{f.icon}</div>
              <div style={{ fontSize: '1.3rem', fontWeight: 700, color: f.color }}>{countFor(f.value)}</div>
              <div style={{ fontSize: '0.68rem', color: 'var(--text-secondary)' }}>{f.label}</div>
            </div>
          ))}
        </div>

        {/* Filters */}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 12, marginBottom: 28, alignItems: 'center' }}>
          {/* Status tabs */}
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            {STATUS_FILTERS.map(f => (
              <button key={f.value} onClick={() => setStatus(f.value)} style={{
                padding: '7px 14px', borderRadius: 40,
                border: `1px solid ${statusFilter === f.value ? f.color : 'rgba(0,255,255,0.15)'}`,
                background: statusFilter === f.value ? `${f.color}18` : 'transparent',
                color: statusFilter === f.value ? f.color : 'var(--text-secondary)',
                cursor: 'pointer', fontSize: '0.8rem', fontWeight: 500,
                display: 'flex', alignItems: 'center', gap: 5,
              }}>
                <span>{f.icon}</span> {f.label}
                {f.value && (
                  <span style={{
                    background: statusFilter === f.value ? `${f.color}30` : 'rgba(255,255,255,0.08)',
                    borderRadius: 20, padding: '1px 6px', fontSize: '0.7rem',
                  }}>{countFor(f.value)}</span>
                )}
              </button>
            ))}
          </div>

          {/* Search */}
          <div style={{
            marginLeft: 'auto', display: 'flex', alignItems: 'center',
            background: 'rgba(10,18,26,0.6)', borderRadius: 40,
            padding: '6px 16px', border: '1px solid rgba(0,255,255,0.2)',
          }}>
            <span style={{ marginRight: 8, color: 'var(--text-muted)' }}>🔍</span>
            <input
              type="text"
              placeholder="Search events, communities..."
              value={search}
              onChange={e => setSearch(e.target.value)}
              style={{
                background: 'transparent', border: 'none',
                color: 'var(--text-primary)', fontSize: '0.85rem',
                outline: 'none', minWidth: 220,
              }}
            />
            {search && (
              <button onClick={() => setSearch('')} style={{ background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', marginLeft: 8 }}>✕</button>
            )}
          </div>
        </div>

        {/* Content */}
        {loading ? (
          <div className="loading-screen"><div className="spinner" /></div>
        ) : filtered.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '60px 20px', background: 'rgba(10,18,26,0.4)', borderRadius: 24, border: '1px solid rgba(0,255,255,0.1)' }}>
            <div style={{ fontSize: '3rem', marginBottom: 16 }}>📅</div>
            <div style={{ fontSize: '1rem', marginBottom: 8 }}>No events found</div>
            <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Try adjusting your filters or search term</div>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            {filtered.map(ev => (
              <div key={ev._id} style={{
                background: 'rgba(10,18,26,0.5)', backdropFilter: 'blur(10px)',
                borderRadius: 16, overflow: 'hidden',
                border: `1px solid ${STATUS_COLOR[ev.status] || '#333'}30`,
                borderLeft: `4px solid ${STATUS_COLOR[ev.status] || '#333'}`,
                transition: 'all 0.2s',
              }}>
                <div style={{ padding: '20px 24px' }}>
                  <div style={{ display: 'flex', gap: 16, alignItems: 'flex-start', flexWrap: 'wrap' }}>

                    {/* Icon */}
                    <div style={{
                      width: 48, height: 48, flexShrink: 0, borderRadius: 10,
                      background: `linear-gradient(135deg, ${STATUS_COLOR[ev.status] || '#666'}33, transparent)`,
                      border: `1px solid ${STATUS_COLOR[ev.status] || '#666'}44`,
                      display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.4rem',
                    }}>📅</div>

                    {/* Main info */}
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 6, flexWrap: 'wrap' }}>
                        <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: 700 }}>{ev.title}</h3>
                        <span style={{
                          background: `${STATUS_COLOR[ev.status]}22`,
                          color: STATUS_COLOR[ev.status] || '#888',
                          border: `1px solid ${STATUS_COLOR[ev.status]}44`,
                          borderRadius: 100, padding: '2px 10px',
                          fontSize: '0.72rem', fontWeight: 600, flexShrink: 0,
                        }}>
                          {STATUS_LABEL[ev.status] || ev.status}
                        </span>
                        <span style={{
                          background: 'rgba(139,92,246,0.12)', color: 'var(--purple-light)',
                          border: '1px solid rgba(139,92,246,0.25)',
                          borderRadius: 100, padding: '2px 10px', fontSize: '0.72rem', fontWeight: 600,
                        }}>
                          {ev.category}
                        </span>
                      </div>

                      <p style={{ margin: '0 0 10px', fontSize: '0.82rem', color: 'var(--text-secondary)', lineHeight: 1.5 }}>
                        {ev.description?.substring(0, 160)}{ev.description?.length > 160 ? '...' : ''}
                      </p>

                      <div style={{ display: 'flex', gap: 20, fontSize: '0.76rem', color: 'var(--text-muted)', flexWrap: 'wrap' }}>
                        <span>📅 {fmt(ev.startDate)}</span>
                        {ev.venue && <span>📍 {ev.venue}</span>}
                        {ev.isVirtual && <span>💻 Virtual</span>}
                        <span style={{ color: 'var(--cyan-accent)', fontWeight: 600 }}>
                          🏛️ {ev.community?.name || '—'}
                        </span>
                        <span>👤 {ev.createdBy?.name || '—'}</span>
                      </div>

                      {ev.status === 'rejected' && ev.rejectionReason && (
                        <div style={{
                          marginTop: 10, padding: '6px 10px',
                          background: 'rgba(239,68,68,0.08)', borderRadius: 8,
                          border: '1px solid rgba(239,68,68,0.2)',
                          fontSize: '0.78rem', color: '#ef4444',
                          display: 'flex', gap: 6,
                        }}>
                          <span>⚠️</span>
                          <span><strong>Rejection reason:</strong> {ev.rejectionReason}</span>
                        </div>
                      )}
                    </div>

                    {/* Actions */}
                    <div style={{ display: 'flex', gap: 8, alignItems: 'flex-start', flexShrink: 0 }}>
                      {ev.status === 'pending_approval' && (
                        <>
                          <button
                            onClick={() => approveEvent(ev._id, ev.title)}
                            style={{
                              padding: '8px 18px', borderRadius: 10,
                              background: 'linear-gradient(135deg, #10b981, #059669)',
                              border: 'none', color: 'white',
                              cursor: 'pointer', fontSize: '0.8rem', fontWeight: 600,
                              display: 'flex', alignItems: 'center', gap: 5,
                            }}
                          >
                            ✓ Approve
                          </button>
                          <button
                            onClick={() => rejectEvent(ev._id, ev.title)}
                            style={{
                              padding: '8px 18px', borderRadius: 10,
                              background: 'linear-gradient(135deg, #ef4444, #dc2626)',
                              border: 'none', color: 'white',
                              cursor: 'pointer', fontSize: '0.8rem', fontWeight: 600,
                              display: 'flex', alignItems: 'center', gap: 5,
                            }}
                          >
                            ✗ Reject
                          </button>
                        </>
                      )}
                      {ev.status === 'rejected' && (
                        <button
                          onClick={() => approveEvent(ev._id, ev.title)}
                          style={{
                            padding: '8px 18px', borderRadius: 10,
                            background: 'linear-gradient(135deg, #10b981, #059669)',
                            border: 'none', color: 'white',
                            cursor: 'pointer', fontSize: '0.8rem', fontWeight: 600,
                          }}
                        >
                          ✓ Approve Anyway
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
